import React, { useState } from "react";
import Layout from "../layout/Layout";
import API from "../services/api";
import "../styles/predictor.css";

function PlacementPredictor() {
  const [cgpa, setCgpa] = useState("");
  const [skills, setSkills] = useState("");
  const [result, setResult] = useState("");

  const predictPlacement = async () => {
    try {
      const res = await API.post("/predict", {
        cgpa,
        skills,
      });

      const prediction = res.data.prediction;

      if (prediction === 1) {
        setResult("High Chance of Placement 🚀");
      } else {
        setResult("Low Chance of Placement ⚠️");
      }
    } catch (error) {
      console.log(error);
      setResult("Prediction failed");
    }
  };

  return (
    <Layout>
      <div className="predictor-container">
        <div className="predictor-card">
          <h1 className="predictor-title">AI Placement Predictor</h1>

          <input
            className="predictor-input"
            placeholder="Enter CGPA"
            value={cgpa}
            onChange={(e) => setCgpa(e.target.value)}
          />

          <input
            className="predictor-input"
            placeholder="Number of Skills"
            value={skills}
            onChange={(e) => setSkills(e.target.value)}
          />

          <button className="predictor-button" onClick={predictPlacement}>
            Predict Placement
          </button>

          {result && <div className="predictor-result">{result}</div>}
        </div>
      </div>
    </Layout>
  );
}

export default PlacementPredictor;
